import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function StudentMarks() {
  const { user }  = useAuth();
  const [data, setData]     = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/student/marks')
      .then(res => { setData(res.data.subjects); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  const SubjectRow = ({ group }) => {
    const { subject, mid1, mid2, finalMarks, finalVisible } = group;
    const statusBadge = (m) => {
      if (!m) return <span className="badge badge-gray">—</span>;
      if (m.isLocked) return <span className="badge badge-red">🔒 Locked</span>;
      if (m.status === 'approved') return <span className="badge badge-green">✅ Approved</span>;
      if (m.status === 'submitted') return <span className="badge badge-yellow">⏳ Pending</span>;
      if (m.status === 'rejected') return <span className="badge badge-red">❌ Rejected</span>;
      return null;
    };

    const MidDetail = ({ m, label }) => {
      if (!m) return (
        <td colSpan={4} style={{ textAlign:'center', color:'var(--text-muted)', fontSize:12 }}>Not entered</td>
      );
      return (
        <>
          <td style={{ fontSize:12 }}>
            <div>Q1:{m.q1} Q2:{m.q2} → <strong>{m.bestQ1Q2}</strong></div>
            <div>Q3:{m.q3} Q4:{m.q4} → <strong>{m.bestQ3Q4}</strong></div>
            <div>Q5:{m.q5} Q6:{m.q6} → <strong>{m.bestQ5Q6}</strong></div>
            <div style={{ color:'var(--text-muted)' }}>Total: {m.questionTotal}÷2={m.questionHalf}</div>
          </td>
          <td style={{ textAlign:'center' }}>{m.assignmentMarks}/5</td>
          <td style={{ textAlign:'center' }}>{m.shaMarks}/10</td>
          <td style={{ textAlign:'center' }}>
            <strong style={{ fontSize:15, color: m.totalMarks >= 18 ? 'var(--success)' : m.totalMarks < 12 ? 'var(--danger)' : 'var(--warning)' }}>
              {m.totalMarks}/30
            </strong>
          </td>
        </>
      );
    };

    return (
      <div className="card mt-16">
        <div className="card-header">
          <div>
            <span className="card-title">{subject?.name}</span>
            <span style={{ marginLeft:8, fontSize:12, color:'var(--text-muted)' }}>{subject?.code}</span>
          </div>
          <div className="gap-8">
            {finalVisible && (
              <span className="badge badge-purple" style={{ fontSize:13, padding:'4px 14px' }}>
                🏆 Final: {finalMarks}/30
              </span>
            )}
          </div>
        </div>

        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Exam</th>
                <th>Question Breakdown</th>
                <th>Asgn /5</th>
                <th>SHA /10</th>
                <th>Total /30</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {/* Mid-1 */}
              <tr style={{ background: '#fafbff' }}>
                <td><span className="badge badge-blue fw-600">Mid-1</span></td>
                <MidDetail m={mid1} label="Mid-1" />
                <td>{statusBadge(mid1)}</td>
              </tr>
              {/* Mid-2 */}
              <tr>
                <td><span className="badge badge-purple fw-600">Mid-2</span></td>
                <MidDetail m={mid2} label="Mid-2" />
                <td>{statusBadge(mid2)}</td>
              </tr>

              {/* Final Row */}
              {finalVisible && (
                <tr style={{ background:'#f0fdf4', borderTop:'2px solid #bbf7d0' }}>
                  <td colSpan={4} style={{ textAlign:'right', paddingRight:16, fontWeight:600, fontSize:13 }}>
                    Final = 80% × {Math.max(mid1?.totalMarks||0, mid2?.totalMarks||0)} + 20% × {Math.min(mid1?.totalMarks||0, mid2?.totalMarks||0)} =
                  </td>
                  <td>
                    <strong style={{ fontSize:18, color:'var(--success)' }}>{finalMarks}/30</strong>
                  </td>
                  <td><span className="badge badge-green">✅ Final</span></td>
                </tr>
              )}

              {/* Waiting for both mids */}
              {!finalVisible && (mid1?.isLocked || mid2?.isLocked) && !(mid1?.isLocked && mid2?.isLocked) && (
                <tr style={{ background:'#fffbeb' }}>
                  <td colSpan={6} style={{ textAlign:'center', color:'#92400e', fontSize:12, padding:'10px' }}>
                    ⏳ Final marks will be shown once HOD locks <strong>both</strong> Mid-1 and Mid-2
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">My Marks</div>
          <div className="page-subtitle">Semester {user?.semester} — {user?.department?.name}</div>
        </div>
      </div>

      <div className="info-box">
        📌 Final marks = <strong>80%</strong> of the higher mid + <strong>20%</strong> of the lower mid.
        Visible only after HOD locks both Mid-1 and Mid-2.
      </div>

      {data.length === 0 ? (
        <div className="card mt-16">
          <div className="empty-state">
            <div className="empty-icon">📊</div>
            <div className="empty-text">No marks available yet</div>
            <div className="empty-subtext">Marks appear here after faculty submits and HOD approves them</div>
          </div>
        </div>
      ) : (
        data.map(group => <SubjectRow key={group.subject?._id} group={group} />)
      )}
    </div>
  );
}
